package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import java.lang.reflect.Method;

public class CSVFormatTest {

    @Test
    void testToStringArray_nullInput() throws Exception {
        CSVFormat csvFormat = CSVFormat.DEFAULT;
        Method toStringArrayMethod = CSVFormat.class.getDeclaredMethod("toStringArray", Object[].class);
        toStringArrayMethod.setAccessible(true);

        String[] result = (String[]) toStringArrayMethod.invoke(csvFormat, new Object[] { null });
        assertNull(result);
    }

    @Test
    void testToStringArray_emptyArray() throws Exception {
        CSVFormat csvFormat = CSVFormat.DEFAULT;
        Method toStringArrayMethod = CSVFormat.class.getDeclaredMethod("toStringArray", Object[].class);
        toStringArrayMethod.setAccessible(true);

        Object[] input = new Object[0];
        String[] result = (String[]) toStringArrayMethod.invoke(csvFormat, new Object[] { input });

        assertNotNull(result);
        assertEquals(0, result.length);
    }

    @Test
    void testToStringArray_withNonNullValues() throws Exception {
        CSVFormat csvFormat = CSVFormat.DEFAULT;
        Method toStringArrayMethod = CSVFormat.class.getDeclaredMethod("toStringArray", Object[].class);
        toStringArrayMethod.setAccessible(true);

        Object[] input = new Object[]{"abc", 123, 45.6, true, 'z'};
        String[] result = (String[]) toStringArrayMethod.invoke(csvFormat, new Object[] { input });

        assertNotNull(result);
        assertEquals(input.length, result.length);
        assertEquals("abc", result[0]);
        assertEquals("123", result[1]);
        assertEquals("45.6", result[2]);
        assertEquals("true", result[3]);
        assertEquals("z", result[4]);
    }

    @Test
    void testToStringArray_withNullElements() throws Exception {
        CSVFormat csvFormat = CSVFormat.DEFAULT;
        Method toStringArrayMethod = CSVFormat.class.getDeclaredMethod("toStringArray", Object[].class);
        toStringArrayMethod.setAccessible(true);

        Object[] input = new Object[]{null, "text", null};
        String[] result = (String[]) toStringArrayMethod.invoke(csvFormat, new Object[] { input });

        assertNotNull(result);
        assertEquals(input.length, result.length);
        assertNull(result[0]);
        assertEquals("text", result[1]);
        assertNull(result[2]);
    }
}
